document.addEventListener("DOMContentLoaded",(()=>{const e='<%= typeof appDate !== "undefined" ? appDate : "" %>',t=document.getElementById("selectedAppDate");function formatDate(e){if(!e)return"";try{const t=new Date(e),a=String(t.getDate()).padStart(2,"0");return`${a}/${String(t.getMonth()+1).padStart(2,"0")}/${t.getFullYear()}`}catch(t){return e}}t&&(e&&(t.innerHTML=`<span class="header-app-style-other">Ημερομηνία : ${formatDate(e)}</span>`),setTimeout((()=>{(async()=>{try{const e=document.querySelector('input[name="_csrf"]')?.value||document.querySelector('meta[name="csrf-token"]')?.content,a=await fetch("/api/appDate",{method:"GET",headers:{"Content-Type":"application/json",...e&&{"CSRF-Token":e}},credentials:"include"});if(401===a.status)return void(t.innerHTML='<span class="header-app-style-other">Ημερομηνία : </span>');if(!a.ok)throw new Error(`HTTP ${a.status}: ${a.statusText}`);const n=a.headers.get("content-type");if(!n||!n.includes("application/json"))return;const r=await a.text();if(!r||""===r.trim())return;const s=JSON.parse(r);s&&s.appDate?t.innerHTML=`<span class="header-app-style-other">Ημερομηνία : ${formatDate(s.appDate)}</span>`:t.innerHTML='<span class="header-app-style-other">Ημερομηνία : -</span>'}catch(e){console.error("Πρόβλημα κατά την εμφάνιση της ημερομηνίας:",e),t.innerHTML='<span class="header-app-style-other">Ημερομηνία : -</span>'}})()}),100))}));